public boolean hasAllCodes(String s, int k) {
    int need = 1 << k;
    Set<String> got = new HashSet<>();

    for (int i = 0; i <= s.length() - k; i++) {
        got.add(s.substring(i, i + k));
    }

    return got.size() == need;
}
```

